const ok = $json.success === true;
const skipped = $json.skipped === true;
const slug = $json.slug || '?';
const section = $json.section || '?';
const v = $json.video_result || {};
const longUrl = v.long_url || v.longform_url || v.long_youtube?.url || '';
const shortUrl = v.short_url || v.shorts_url || v.short_youtube?.url || '';

if (!ok && !skipped) {
  const detail = $json.error || v.error || v.output || JSON.stringify($json).slice(0, 500);
  throw new Error(`Shorts auto 실패: ${slug} [${section}] ${detail}`);
}

let text;
if (skipped) {
  text = `⏸ Shorts auto skipped: ${$json.reason || 'unknown'}`;
} else {
  text = `🎬 Shorts auto 생성: ${slug} [${section}]\nLongform: ${longUrl || '-'}\nShort: ${shortUrl || '-'}`;
}
return [{ json: { text, success: ok, skipped, slug, section, longUrl, shortUrl } }];
